package org.apache.commons.math3.random;


import org.apache.commons.math3.exception.NotStrictlyPositiveException;
import org.apache.commons.math3.util.FastMath;

/** Base class for random number generators that generates bits streams.
 *
 * @version $Id$
 * @since 2.0
 */
public abstract class BitsStreamGenerator
    implements RandomGenerator {
    /** Serializable version identifier */
    /** Next gaussian. */
    private double nextGaussian;

    /**
     * Creates a new random number generator.
     */
    public BitsStreamGenerator() {
        nextGaussian = Double.NaN;
    }

    /** {@inheritDoc} */
    public abstract void setSeed(int seed);

    /** {@inheritDoc} */
    public abstract void setSeed(int[] seed);

    /** {@inheritDoc} */
    public abstract void setSeed(long seed);

    /** Generate next pseudorandom number.
     * <p>This method is the core generation algorithm. It is used by all the
     * public generation methods for the various primitive types {@link
     * #nextBoolean()}, {@link #nextBytes(byte[])}, {@link #nextDouble()},
     * {@link #nextFloat()}, {@link #nextGaussian()}, {@link #nextInt()},
     * {@link #next(int)} and {@link #nextLong()}.</p>
     * @param bits number of random bits to produce
     * @return random bits generated
     */
    protected abstract int next(int bits);

    /** {@inheritDoc} */
    public boolean nextBoolean() {
        return next(1) != 0;
    }

    /** {@inheritDoc} */
    public void nextBytes(byte[] bytes) {
        int i = 0;
        final int iEnd = bytes.length - 3;
        while (i < iEnd) {
            final int random = next(32);
            bytes[i]     = (byte) (random & 0xff);
            bytes[i + 1] = (byte) ((random >>  8) & 0xff);
            bytes[i + 2] = (byte) ((random >> 16) & 0xff);
            bytes[i + 3] = (byte) ((random >> 24) & 0xff);
            i += 4;
        }
        int random = next(32);
        while (i < bytes.length) {
            bytes[i++] = (byte) (random & 0xff);
            random     = random >> 8;
        }
    }

    /** {@inheritDoc} */
    public double nextDouble() {
        final long high = ((long) next(26)) << 26;
        final int  low  = next(26);
        return (high | low) * 0x1.0p-52d;
    }

    /** {@inheritDoc} */
    public float nextFloat() {
        return next(23) * 0x1.0p-23f;
    }

    /** {@inheritDoc} */
    public double nextGaussian() {

        final double random;
        if (Double.isNaN(nextGaussian)) {
            // generate a new pair of gaussian numbers
            final double x = nextDouble();
            final double y = nextDouble();
            final double alpha = 2 * FastMath.PI * x;
            final double r      = FastMath.sqrt(-2 * FastMath.log(y));
            random       = r * FastMath.cos(alpha);
            nextGaussian = r * FastMath.sin(alpha);
        } else {
            // use the second element of the pair already generated
            random = nextGaussian;
            nextGaussian = Double.NaN;
        }

        return random;

    }

    /** {@inheritDoc} */
    public int nextInt() {
        return next(32);
    }

    /**
     * {@inheritDoc}
     * <p>This default implementation is copied from Apache Harmony
     * java.util.Random (r929253).</p>
     *
     * <p>Implementation notes: <ul>
     * <li>If n is a power of 2, this method returns
     * {@code (int) ((n * (long) next(31)) >> 31)}.</li>
     *
     * <li>If n is not a power of 2, what is returned is {@code next(31) % n}
     * with {@code next(31)} values rejected (i.e. regenerated) until a
     * value that is larger than the remainder of {@code Integer.MAX_VALUE / n}
     * is generated. Rejection of this initial segment is necessary to ensure
     * a uniform distribution.</li></ul></p>
     */
    public int nextInt(int n) throws IllegalArgumentException {
        if (n > 0) {
            if ((n & -n) == n) {
                return (int) ((n * (long) next(31)) >> 31);
            }
            int bits;
            int val;
            do {
                bits = next(31);
                val = bits % n;
            } while (bits - val + (n - 1) < 0);
            return val;
        }
        throw new NotStrictlyPositiveException(n);
    }

    /** {@inheritDoc} */
    public long nextLong() {
        final long high  = ((long) next(32)) << 32;
        final long  low  = ((long) next(32)) & 0xffffffffL;
        return high | low;
    }

    /**
     * Clears the cache used by the default implementation of
     * {@link #nextGaussian}.
     */
    public void clear() {
        nextGaussian = Double.NaN;
    }

}

package org.apache.commons.math3.random.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.math3.distribution.GammaDistribution;
import org.apache.commons.math3.random.RandomGenerator;
import org.apache.commons.math3.distribution.RealDistribution;

import java.io.*;

import static org.junit.Assert.assertEquals;

public class StepDefs {
    private GammaDistribution originalDistribution;
    private GammaDistribution clonedDistribution;
    private double firstSample;

    @Given("a GammaDistribution with shape {double} and scale {double}")
    public void a_gamma_distribution_with_shape_and_scale(double shape, double scale) {
        originalDistribution = new GammaDistribution(shape, scale);
    }

    @Given("the distribution is seeded with a fixed seed {int}")
    public void the_distribution_is_seeded_with_a_fixed_seed(int seed) {
        RandomGenerator rng = new org.apache.commons.math3.random.Well19937c();
        rng.setSeed(seed);
        // Create new distribution with seeded random generator
        originalDistribution = new GammaDistribution(rng, originalDistribution.getShape(),
                originalDistribution.getScale(), GammaDistribution.DEFAULT_INVERSE_ABSOLUTE_ACCURACY);
    }

    @Given("I sample the distribution once to advance the RNG state")
    public void i_sample_the_distribution_once() {
        firstSample = originalDistribution.sample();
    }

    @When("I clone the distribution via serialization")
    public void i_clone_the_distribution_via_serialization() {
        try {
            // Serialize the distribution
            ByteArrayOutputStream byteOutputStream = new ByteArrayOutputStream();
            ObjectOutputStream objectOutputStream = new ObjectOutputStream(byteOutputStream);
            objectOutputStream.writeObject(originalDistribution);
            objectOutputStream.close();

            // Deserialize the distribution
            byte[] serializedBytes = byteOutputStream.toByteArray();
            ByteArrayInputStream byteInputStream = new ByteArrayInputStream(serializedBytes);
            ObjectInputStream objectInputStream = new ObjectInputStream(byteInputStream);
            clonedDistribution = (GammaDistribution) objectInputStream.readObject();
            objectInputStream.close();
        } catch (Exception e) {
            throw new RuntimeException("Error during serialization/deserialization", e);
        }
    }

    @Then("the next sample from the original distribution should equal the next sample from the cloned distribution")
    public void the_next_sample_from_the_original_distribution_should_equal_the_next_sample_from_the_cloned_distribution() {
        try {
            double originalNextSample = originalDistribution.sample();
            double clonedNextSample = clonedDistribution.sample();

            assertEquals("The next samples from original and cloned distributions should be equal",
                        originalNextSample, clonedNextSample, 1e-10);
        } catch (Exception e) {
            throw new RuntimeException("Error getting samples", e);
        }
    }
}

